Certainly! Here is an example of an MQL4 Expert Advisor that fulfills your requirements:

```mql4
// Input parameters
input double TP = 0; // Take Profit level
input double SL = 0; // Stop Loss level
input double LotSize = 0.01; // Lot size
input int RSI_Period = 14; // RSI period
input int RSI_Threshold = 70; // RSI threshold

// Indicator handles
int arrowHandle; // Arrow object handle

// Initialize the Expert Advisor
void OnInit()
{
    arrowHandle = ObjectsCreate(0, OBJ_ARROW, 0, 0, 0);
    ObjectsSetInteger(0, "ArrowCode", 233);
    ObjectsSetInteger(0, "ArrowSize", 2);
    ObjectsSetInteger(0, "ArrowType", 2);
    ObjectSet(0, OBJPROP_COLOR, clrRed);
}

// Start trading
void OnTick()
{
    double rsiValue = iRSI(Symbol(), PERIOD_CURRENT, RSI_Period, PRICE_CLOSE, 0);

    // Check if RSI goes above the threshold
    if (rsiValue > RSI_Threshold)
    {
        double entryPrice = Ask;

        // Place a sell order
        int ticket = OrderSend(Symbol(), OP_SELL, LotSize, entryPrice, 0, 0, 0, "", 0, 0, clrNONE);

        // Set Take Profit and Stop Loss levels for the order
        if (ticket > 0)
        {
            OrderSelect(ticket, SELECT_BY_TICKET);
            OrderModify(ticket, 0, entryPrice - SL * Point, entryPrice + TP * Point, 0, CLR_NONE);
        }

        // Plot the arrow above the entry price
        ObjectSetDouble(arrowHandle, OBJPROP_PRICE1, entryPrice + (Point * 10));
        ObjectSetString(arrowHandle, OBJPROP_TEXT, "Sell");
        ObjectSet(arrowHandle, OBJPROP_TIME1, Time[0] + PeriodSeconds(1));
        ObjectSet(arrowHandle, OBJPROP_SELECTED, false);
    }
}
```

Please note that this is just a basic example that covers your requirements. You may need to further optimize and add error handling as per your specific trading strategy.

